from django.conf import settings
from django.contrib.auth import login
from django.contrib.auth.models import User
from django.http import HttpResponseBadRequest
from django.shortcuts import redirect
from django.views import View
from lxml import etree
import base64
import xmlsec

class SAMLResponseView(View):
    def post(self, request):
        saml_response = request.POST.get('SAMLResponse')
        if not saml_response:
            return HttpResponseBadRequest("Missing SAMLResponse")

        decoded_response = base64.b64decode(saml_response)
        xml_response = etree.fromstring(decoded_response)

        if not self.validate_xml_structure(xml_response):
            return HttpResponseBadRequest("Invalid SAML Response Structure")

        name_id = self.extract_name_id(xml_response)
        attributes = self.extract_attributes(xml_response)

        user, created = User.objects.get_or_create(username=name_id)
        if created:
            user.first_name = attributes.get('firstName', '')
            user.last_name = attributes.get('lastName', '')
            user.email = attributes.get('email', '')
            user.save()

        login(request, user)
        return redirect('home')

    def validate_xml_structure(self, xml_response):
        # Basic structure validation
        try:
            # Check for the presence of the Assertion element
            assertion = xml_response.find('.//{urn:oasis:names:tc:SAML:2.0:assertion}Assertion')
            return assertion is not None
        except Exception:
            return False

    def extract_name_id(self, xml_response):
        name_id_element = xml_response.find('.//{urn:oasis:names:tc:SAML:2.0:assertion}NameID')
        return name_id_element.text if name_id_element is not None else None

    def extract_attributes(self, xml_response):
        attributes = {}
        for attr in xml_response.findall('.//{urn:oasis:names:tc:SAML:2.0:assertion}Attribute'):
            attr_name = attr.get('Name')
            attr_value = attr.find('{urn:oasis:names:tc:SAML:2.0:assertion}AttributeValue')
            if attr_value is not None:
                attributes[attr_name] = attr_value.text
        return attributes